        if (!Files.exists(Paths.get(configPath))) {
            throw new IOException("Configuration file does not exist: " + configPath);
        }

        // Create transformer factory and transformer for identity transform
        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        // Prevent XXE attacks by disabling external entities and DTDs
        try {
            transformerFactory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            transformerFactory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            transformerFactory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        } catch (Exception e) {
            // If features are not supported, continue with default settings
            // but log or handle appropriately in production
        }

        Transformer transformer = transformerFactory.newTransformer();

        // Perform identity transform from file to DOM
        StreamSource source = new StreamSource(configPath);
        DOMResult result = new DOMResult();
        transformer.transform(source, result);

        return (Document) result.getNode();
    }
}
